Storing sensitive data like SSNs directly in a database without encryption is extremely dangerous. The 2022 Optus breach exposed 9.8 million customer records including passport numbers because sensitive data was stored in plaintext, resulting in $140M+ in damages.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

// DANGEROUS: Storing SSN in plaintext
app.post('/api/users', async (req, res) => {
  const { name, email, ssn, dateOfBirth } = req.body;

  try {
    // SSN stored directly without any encryption!
    const result = await pool.query(
      'INSERT INTO users (name, email, ssn, date_of_birth) VALUES ($1, $2, $3, $4) RETURNING id',
      [name, email, ssn, dateOfBirth]
    );

    res.json({ userId: result.rows[0].id, message: 'User created' });
  } catch (error) {
    res.status(500).json({ error: 'Database error' });
  }
});

// Retrieves plaintext SSN - massive exposure risk
app.get('/api/users/:id', async (req, res) => {
  const result = await pool.query('SELECT * FROM users WHERE id = $1', [req.params.id]);
  res.json(result.rows[0]); // Returns plaintext SSN!
});
```

**Attack Scenario**:
```sql
-- If attacker gains database access (SQL injection, backup theft, insider threat):
SELECT name, email, ssn, date_of_birth FROM users;
-- Returns all SSNs in plaintext immediately usable for identity theft
```

**Why This Is Dangerous**:
- SSNs stored in plaintext are immediately usable if database is breached
- Database backups contain plaintext sensitive data
- Any user with database access (DBAs, developers) can view SSNs
- SQL injection would expose all sensitive data instantly
- Violates PCI-DSS, HIPAA, GDPR, and most compliance frameworks

**SECURE VERSION**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

// Encryption configuration - key should be in secure key management
const ENCRYPTION_KEY = Buffer.from(process.env.ENCRYPTION_KEY, 'hex'); // 32 bytes for AES-256
const IV_LENGTH = 16;
const ALGORITHM = 'aes-256-gcm';
const AUTH_TAG_LENGTH = 16;

function encryptSensitiveData(plaintext) {
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, ENCRYPTION_KEY, iv);

  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  const authTag = cipher.getAuthTag();

  // Format: iv:authTag:encryptedData
  return `${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted}`;
}

function decryptSensitiveData(encryptedData) {
  const parts = encryptedData.split(':');
  if (parts.length !== 3) {
    throw new Error('Invalid encrypted data format');
  }

  const iv = Buffer.from(parts[0], 'hex');
  const authTag = Buffer.from(parts[1], 'hex');
  const encrypted = parts[2];

  const decipher = crypto.createDecipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
  decipher.setAuthTag(authTag);

  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

// SECURE: Encrypt SSN before storage
app.post('/api/users', async (req, res) => {
  const { name, email, ssn, dateOfBirth } = req.body;

  try {
    // Encrypt SSN before storing
    const encryptedSsn = encryptSensitiveData(ssn);

    const result = await pool.query(
      'INSERT INTO users (name, email, ssn_encrypted, date_of_birth) VALUES ($1, $2, $3, $4) RETURNING id',
      [name, email, encryptedSsn, dateOfBirth]
    );

    res.json({ userId: result.rows[0].id, message: 'User created securely' });
  } catch (error) {
    console.error('User creation error:', error.message);
    res.status(500).json({ error: 'Failed to create user' });
  }
});
```

**Key Security Controls**:
- **AES-256-GCM encryption**: Industry-standard authenticated encryption protects data confidentiality and integrity
- **Random IV per encryption**: Prevents pattern analysis attacks; same plaintext produces different ciphertext
- **Authentication tag (GCM)**: Detects tampering with encrypted data, prevents chosen-ciphertext attacks
- **Key separation**: Encryption key stored separately from encrypted data

Excellent question. Key management is often the weakest link in encryption systems. Hardcoded keys or poor rotation practices have caused major breaches including the 2023 LastPass incident where encryption keys were compromised.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const crypto = require('crypto');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');
const winston = require('winston');

const app = express();
app.use(express.json());

// Structured security logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Key Management Service integration
class EncryptionKeyManager {
  constructor() {
    this.secretsClient = new SecretsManagerClient({ region: process.env.AWS_REGION });
    this.keyCache = new Map();
    this.cacheExpiry = 3600000; // 1 hour cache
  }

  async getActiveKey() {
    const cacheKey = 'active_encryption_key';
    const cached = this.keyCache.get(cacheKey);

    if (cached && Date.now() < cached.expiry) {
      return cached.key;
    }

    try {
      const command = new GetSecretValueCommand({
        SecretId: process.env.ENCRYPTION_KEY_SECRET_ARN
      });

      const response = await this.secretsClient.send(command);
      const secrets = JSON.parse(response.SecretString);

      const keyData = {
        key: Buffer.from(secrets.activeKey, 'hex'),
        keyId: secrets.activeKeyId,
        version: secrets.keyVersion
      };

      this.keyCache.set(cacheKey, {
        key: keyData,
        expiry: Date.now() + this.cacheExpiry
      });

      return keyData;
    } catch (error) {
      logger.error('Failed to retrieve encryption key', {
        error: error.message,
        component: 'KeyManager'
      });
      throw new Error('Encryption service unavailable');
    }
  }

  async getKeyById(keyId) {
    // Retrieve specific key version for decryption of old data
    const command = new GetSecretValueCommand({
      SecretId: process.env.ENCRYPTION_KEY_SECRET_ARN,
      VersionId: keyId
    });

    const response = await this.secretsClient.send(command);
    const secrets = JSON.parse(response.SecretString);
    return Buffer.from(secrets.key, 'hex');
  }

  clearCache() {
    this.keyCache.clear();
    logger.info('Encryption key cache cleared', { component: 'KeyManager' });
  }
}

const keyManager = new EncryptionKeyManager();

// Encryption service with key versioning
class FieldLevelEncryption {
  constructor(keyManager) {
    this.keyManager = keyManager;
    this.algorithm = 'aes-256-gcm';
    this.ivLength = 16;
  }

  async encrypt(plaintext, fieldName) {
    const keyData = await this.keyManager.getActiveKey();
    const iv = crypto.randomBytes(this.ivLength);

    const cipher = crypto.createCipheriv(this.algorithm, keyData.key, iv);
    cipher.setAAD(Buffer.from(fieldName)); // Bind encryption to field name

    let encrypted = cipher.update(plaintext, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    const authTag = cipher.getAuthTag();

    // Include key version for future decryption after rotation
    const envelope = {
      v: 1, // Envelope version
      kid: keyData.keyId,
      iv: iv.toString('hex'),
      tag: authTag.toString('hex'),
      data: encrypted
    };

    logger.info('Data encrypted', {
      fieldName,
      keyId: keyData.keyId,
      component: 'Encryption'
    });

    return Buffer.from(JSON.stringify(envelope)).toString('base64');
  }

  async decrypt(encryptedEnvelope, fieldName) {
    try {
      const envelope = JSON.parse(Buffer.from(encryptedEnvelope, 'base64').toString('utf8'));

      // Get the specific key version used for encryption
      const key = await this.keyManager.getKeyById(envelope.kid);
      const iv = Buffer.from(envelope.iv, 'hex');
      const authTag = Buffer.from(envelope.tag, 'hex');

      const decipher = crypto.createDecipheriv(this.algorithm, key, iv);
      decipher.setAuthTag(authTag);
      decipher.setAAD(Buffer.from(fieldName)); // Verify field binding

      let decrypted = decipher.update(envelope.data, 'hex', 'utf8');
      decrypted += decipher.final('utf8');

      return decrypted;
    } catch (error) {
      logger.error('Decryption failed', {
        fieldName,
        error: error.message,
        component: 'Encryption'
      });
      throw new Error('Failed to decrypt sensitive data');
    }
  }
}

const encryption = new FieldLevelEncryption(keyManager);

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: { rejectUnauthorized: true } // Enforce TLS for data in transit
});

// Secure user creation with full encryption
app.post('/api/users', async (req, res) => {
  const { name, email, ssn, dateOfBirth } = req.body;
  const requestId = crypto.randomUUID();

  // Input validation
  if (!ssn || !/^\d{3}-\d{2}-\d{4}$/.test(ssn)) {
    logger.warn('Invalid SSN format', { requestId, component: 'Validation' });
    return res.status(400).json({ error: 'Invalid SSN format' });
  }

  try {
    // Encrypt all PII fields
    const encryptedSsn = await encryption.encrypt(ssn, 'ssn');
    const encryptedDob = await encryption.encrypt(dateOfBirth, 'dateOfBirth');

    // Store only last 4 digits for lookup (tokenization pattern)
    const ssnLastFour = ssn.slice(-4);
    const ssnHash = crypto.createHash('sha256').update(ssn + process.env.SSN_SALT).digest('hex');

    const result = await pool.query(
      `INSERT INTO users (name, email, ssn_encrypted, ssn_last_four, ssn_hash, dob_encrypted, created_at) 
       VALUES ($1, $2, $3, $4, $5, $6, NOW()) RETURNING id`,
      [name, email, encryptedSsn, ssnLastFour, ssnHash, encryptedDob]
    );

    logger.info('User created with encrypted PII', {
      requestId,
      userId: result.rows[0].id,
      component: 'UserService'
    });

    res.json({ userId: result.rows[0].id, message: 'User created securely' });
  } catch (error) {
    logger.error('User creation failed', {
      requestId,
      error: error.message,
      component: 'UserService'
    });
    res.status(500).json({ error: 'Failed to create user' });
  }
});

// Key rotation endpoint (admin only, with proper auth middleware)
app.post('/api/admin/rotate-keys', async (req, res) => {
  // This triggers re-encryption of all data with new key
  // Should be run as background job in production
  keyManager.clearCache();

  logger.info('Key rotation initiated', {
    initiatedBy: req.user?.id,
    component: 'KeyRotation'
  });

  res.json({ message: 'Key rotation initiated' });
});

// Health check for encryption service
app.get('/api/health/encryption', async (req, res) => {
  try {
    const keyData = await keyManager.getActiveKey();
    res.json({
      status: 'healthy',
      keyVersion: keyData.version,
      keyId: keyData.keyId.substring(0, 8) + '...' // Partial for debugging
    });
  } catch (error) {
    res.status(503).json({ status: 'unhealthy', error: 'Key service unavailable' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info('Secure API server started', { port: PORT, component: 'Server' });
});
```

**Defense in Depth Layers**:

1. **Hardware Security Module (HSM) / Cloud KMS Integration**:
```javascript
// AWS KMS for key wrapping - keys never leave HSM
const { KMSClient, GenerateDataKeyCommand } = require('@aws-sdk/client-kms');

class KMSKeyWrapper {
  async generateDataKey() {
    const command = new GenerateDataKeyCommand({
      KeyId: process.env.KMS_CMK_ARN,
      KeySpec: 'AES_256'
    });
    const response = await kmsClient.send(command);
    return {
      plaintext: response.Plaintext,      // Use for encryption
      encrypted: response.CiphertextBlob  // Store this
    };
  }
}
```

2. **Envelope Encryption Pattern**:
```javascript
// Data key encrypted by master key - limits exposure
const envelope = {
  encryptedDataKey: kmsWrappedKey,  // Decrypt via KMS
  iv: iv.toString('hex'),
  ciphertext: encrypted,
  keyVersion: 'v2024-01'
};
```

3. **Automatic Key Rotation Policy**:
```javascript
// Scheduled key rotation with re-encryption job
const cron = require('node-cron');

cron.schedule('0 0 1 */3 *', async () => {
  // Quarterly key rotation
  logger.info('Starting scheduled key rotation');
  await performKeyRotation();
});
```

**Additional Protections**:
- **TLS 1.3 enforced** for all database connections protecting data in transit
- **Field-level encryption** with AAD prevents field swapping attacks
- **Key versioning in ciphertext envelope** enables seamless rotation without re-encrypting all data immediately
- **Salted hashing** for lookups prevents rainbow table attacks on indexed fields
- **Audit logging** of all encryption/decryption operations for compliance
- **Cache expiration** limits window if memory is compromised
- **Separate encryption per field type** prevents cross-field attacks

Storing sensitive data like SSN and credit card numbers in plaintext is extremely dangerous and violates PCI-DSS, GDPR, HIPAA, and other regulations. If an attacker gains database access through SQL injection, backup theft, or insider threat, all sensitive data is immediately exposed.

**VULNERABLE CODE**:

```java
import java.sql.*;

public class UserDataService {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password123";

    public void saveUserData(String name, String ssn, String creditCard) 
            throws SQLException {
        String sql = "INSERT INTO users (name, ssn, credit_card) VALUES (?, ?, ?)";

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
             PreparedStatement stmt = conn.prepareStatement(sql)) {

            // VULNERABLE: Storing sensitive data in plaintext
            stmt.setString(1, name);
            stmt.setString(2, ssn);        // SSN stored as plaintext!
            stmt.setString(3, creditCard); // Credit card stored as plaintext!
            stmt.executeUpdate();
        }
    }

    public String getUserSSN(int userId) throws SQLException {
        String sql = "SELECT ssn FROM users WHERE id = ?";

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
             PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setInt(1, userId);
            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                return rs.getString("ssn"); // Returns plaintext SSN
            }
        }
        return null;
    }
}
```

**Attack Scenario**:
```sql
-- Attacker with read access to database or backup file:
SELECT name, ssn, credit_card FROM users;
-- Result: All sensitive data immediately visible
-- name: John Doe, ssn: 123-45-6789, credit_card: 4111111111111111
```

**Why This Is Dangerous**:
- Database backup theft exposes all customer PII instantly
- SQL injection attacks retrieve plaintext sensitive data
- Insider threats have unrestricted access to sensitive data
- Violates PCI-DSS requirement 3.4 (render PAN unreadable)
- GDPR Article 32 requires appropriate technical measures including encryption

**SECURE VERSION**:

```java
import java.sql.*;
import javax.crypto.Cipher;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.util.Base64;

public class SecureUserDataService {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password123";
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;

    // Key should be loaded from secure key management system (AWS KMS, HashiCorp Vault)
    private final SecretKey encryptionKey;

    public SecureUserDataService(SecretKey key) {
        this.encryptionKey = key;
    }

    public void saveUserData(String name, String ssn, String creditCard) 
            throws Exception {
        String sql = "INSERT INTO users (name, ssn_encrypted, credit_card_encrypted, ssn_iv, cc_iv) VALUES (?, ?, ?, ?, ?)";

        // Generate unique IVs for each field
        byte[] ssnIv = generateIV();
        byte[] ccIv = generateIV();

        // Encrypt sensitive data with AES-256-GCM
        String encryptedSSN = encrypt(ssn, ssnIv);
        String encryptedCC = encrypt(creditCard, ccIv);

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
             PreparedStatement stmt = conn.prepareStatement(sql)) {

            stmt.setString(1, name);
            stmt.setString(2, encryptedSSN);  // Encrypted SSN
            stmt.setString(3, encryptedCC);   // Encrypted credit card
            stmt.setString(4, Base64.getEncoder().encodeToString(ssnIv));
            stmt.setString(5, Base64.getEncoder().encodeToString(ccIv));
            stmt.executeUpdate();
        }
    }

    private byte[] generateIV() {
        byte[] iv = new byte[GCM_IV_LENGTH];
        new SecureRandom().nextBytes(iv);
        return iv;
    }

    private String encrypt(String plaintext, byte[] iv) throws Exception {
        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        GCMParameterSpec parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, encryptionKey, parameterSpec);
        byte[] encrypted = cipher.doFinal(plaintext.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(encrypted);
    }

    private String decrypt(String ciphertext, byte[] iv) throws Exception {
        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        GCMParameterSpec parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.DECRYPT_MODE, encryptionKey, parameterSpec);
        byte[] decrypted = cipher.doFinal(Base64.getDecoder().decode(ciphertext));
        return new String(decrypted, "UTF-8");
    }
}
```

**Key Security Controls**:
- **AES-256-GCM encryption**: Industry-standard authenticated encryption that provides confidentiality and integrity
- **Unique IV per encryption**: Prevents pattern analysis attacks; never reuse IVs with GCM
- **Base64 encoding**: Safe storage of binary encrypted data in database text columns
- **Separate key management**: Encryption key stored outside database (if DB is compromised, key is not)

Excellent question! Hardcoding encryption keys is almost as bad as not encrypting at all. Production systems require secure key management with rotation capabilities, access controls, and audit logging. Here's a production-ready pattern using envelope encryption with AWS KMS.

**PRODUCTION PATTERN**:

```java
import software.amazon.awssdk.services.kms.KmsClient;
import software.amazon.awssdk.services.kms.model.*;
import software.amazon.awssdk.core.SdkBytes;
import javax.crypto.Cipher;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.util.Base64;
import java.sql.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class ProductionEncryptionService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionEncryptionService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;
    private static final String ALGORITHM = "AES/GCM/NoPadding";

    private final KmsClient kmsClient;
    private final String masterKeyId;
    private final DataSource dataSource;

    // Cache for decrypted data encryption keys (DEKs)
    private final com.google.common.cache.Cache<String, SecretKey> dekCache;

    public ProductionEncryptionService(String masterKeyId, DataSource dataSource) {
        this.kmsClient = KmsClient.create();
        this.masterKeyId = masterKeyId;
        this.dataSource = dataSource;

        // Cache DEKs for 5 minutes to reduce KMS calls
        this.dekCache = com.google.common.cache.CacheBuilder.newBuilder()
                .expireAfterWrite(5, java.util.concurrent.TimeUnit.MINUTES)
                .maximumSize(100)
                .build();
    }

    /**
     * Generates a new Data Encryption Key (DEK) using envelope encryption.
     * The DEK is encrypted by AWS KMS master key.
     */
    public EncryptedDataKey generateDataKey() throws Exception {
        GenerateDataKeyRequest request = GenerateDataKeyRequest.builder()
                .keyId(masterKeyId)
                .keySpec(DataKeySpec.AES_256)
                .build();

        GenerateDataKeyResponse response = kmsClient.generateDataKey(request);

        auditLogger.info("Generated new DEK using master key: {}", masterKeyId);

        return new EncryptedDataKey(
                response.plaintext().asByteArray(),
                response.ciphertextBlob().asByteArray()
        );
    }

    /**
     * Encrypts sensitive data using envelope encryption pattern.
     * Returns encrypted data + encrypted DEK (both needed for decryption).
     */
    public EncryptedPayload encryptSensitiveData(String plaintext, String dataClassification) 
            throws Exception {
        // Generate a unique DEK for this encryption operation
        EncryptedDataKey dataKey = generateDataKey();

        // Generate unique IV
        byte[] iv = new byte[GCM_IV_LENGTH];
        new SecureRandom().nextBytes(iv);

        // Encrypt data with plaintext DEK
        SecretKey secretKey = new SecretKeySpec(dataKey.getPlaintextKey(), "AES");
        Cipher cipher = Cipher.getInstance(ALGORITHM);
        GCMParameterSpec parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, parameterSpec);

        // Add AAD (Additional Authenticated Data) for integrity
        cipher.updateAAD(dataClassification.getBytes("UTF-8"));

        byte[] encryptedData = cipher.doFinal(plaintext.getBytes("UTF-8"));

        // Clear plaintext key from memory
        java.util.Arrays.fill(dataKey.getPlaintextKey(), (byte) 0);

        auditLogger.info("Encrypted {} data, classification: {}", 
                plaintext.length(), dataClassification);

        return new EncryptedPayload(
                Base64.getEncoder().encodeToString(encryptedData),
                Base64.getEncoder().encodeToString(dataKey.getEncryptedKey()),
                Base64.getEncoder().encodeToString(iv),
                dataClassification
        );
    }

    /**
     * Decrypts data by first decrypting the DEK via KMS, then decrypting the data.
     */
    public String decryptSensitiveData(EncryptedPayload payload, String requestingUser) 
            throws Exception {
        // Audit log access attempt
        auditLogger.info("Decryption requested by user: {}, classification: {}", 
                requestingUser, payload.getDataClassification());

        // Decrypt the DEK using KMS
        byte[] encryptedDek = Base64.getDecoder().decode(payload.getEncryptedDek());
        SecretKey dek = decryptDataKey(encryptedDek);

        // Decrypt the data
        byte[] iv = Base64.getDecoder().decode(payload.getIv());
        byte[] ciphertext = Base64.getDecoder().decode(payload.getEncryptedData());

        Cipher cipher = Cipher.getInstance(ALGORITHM);
        GCMParameterSpec parameterSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.DECRYPT_MODE, dek, parameterSpec);

        // Verify AAD matches
        cipher.updateAAD(payload.getDataClassification().getBytes("UTF-8"));

        byte[] decryptedData = cipher.doFinal(ciphertext);

        auditLogger.info("Decryption successful for user: {}", requestingUser);

        return new String(decryptedData, "UTF-8");
    }

    private SecretKey decryptDataKey(byte[] encryptedDek) throws Exception {
        String cacheKey = Base64.getEncoder().encodeToString(encryptedDek);

        SecretKey cachedKey = dekCache.getIfPresent(cacheKey);
        if (cachedKey != null) {
            return cachedKey;
        }

        DecryptRequest request = DecryptRequest.builder()
                .ciphertextBlob(SdkBytes.fromByteArray(encryptedDek))
                .keyId(masterKeyId)
                .build();

        DecryptResponse response = kmsClient.decrypt(request);
        SecretKey dek = new SecretKeySpec(response.plaintext().asByteArray(), "AES");

        dekCache.put(cacheKey, dek);
        return dek;
    }

    /**
     * Key rotation: Re-encrypts all data with new DEKs.
     * Old encrypted DEKs still work as KMS maintains key versions.
     */
    public void rotateDataEncryptionKeys(String tableName, String[] encryptedColumns) 
            throws Exception {
        auditLogger.info("Starting key rotation for table: {}", tableName);

        String selectSql = String.format(
                "SELECT id, %s FROM %s WHERE key_version < ?",
                String.join(", ", encryptedColumns), tableName);

        int currentKeyVersion = getCurrentKeyVersion();
        int rotatedCount = 0;

        try (Connection conn = dataSource.getConnection();
             PreparedStatement selectStmt = conn.prepareStatement(selectSql)) {

            selectStmt.setInt(1, currentKeyVersion);
            ResultSet rs = selectStmt.executeQuery();

            while (rs.next()) {
                int id = rs.getInt("id");

                for (String column : encryptedColumns) {
                    String oldEncrypted = rs.getString(column);
                    if (oldEncrypted != null) {
                        // Re-encrypt with new DEK
                        // Implementation omitted for brevity
                        rotatedCount++;
                    }
                }
            }
        }

        auditLogger.info("Key rotation completed. Rotated {} records", rotatedCount);
    }

    private int getCurrentKeyVersion() {
        // Retrieve from configuration or KMS
        return 1;
    }

    // Inner classes for data transfer
    public static class EncryptedDataKey {
        private final byte[] plaintextKey;
        private final byte[] encryptedKey;

        public EncryptedDataKey(byte[] plaintextKey, byte[] encryptedKey) {
            this.plaintextKey = plaintextKey;
            this.encryptedKey = encryptedKey;
        }

        public byte[] getPlaintextKey() { return plaintextKey; }
        public byte[] getEncryptedKey() { return encryptedKey; }
    }

    public static class EncryptedPayload {
        private final String encryptedData;
        private final String encryptedDek;
        private final String iv;
