```go
package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"database/sql"
	"encoding/base64"
	"errors"
	"io"
	"os"

	_ "github.com/lib/pq"
)

type SecureCredentialStore struct {
	db     *sql.DB
	gcm    cipher.AEAD
}

func NewSecureCredentialStore(db *sql.DB) (*SecureCredentialStore, error) {
	// Load encryption key from secure environment variable
	keyStr := os.Getenv("CREDENTIAL_ENCRYPTION_KEY")
	if keyStr == "" {
		return nil, errors.New("encryption key not configured")
	}

	key, err := base64.StdEncoding.DecodeString(keyStr)
	if err != nil || len(key) != 32 {
		return nil, errors.New("invalid encryption key")
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	return &SecureCredentialStore{db: db, gcm: gcm}, nil
}

func (s *SecureCredentialStore) encrypt(plaintext string) (string, error) {
	nonce := make([]byte, s.gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", err
	}

	ciphertext := s.gcm.Seal(nonce, nonce, []byte(plaintext), nil)
	return base64.StdEncoding.EncodeToString(ciphertext), nil
}

func (s *SecureCredentialStore) decrypt(encoded string) (string, error) {
	ciphertext, err := base64.StdEncoding.DecodeString(encoded)
	if err != nil {
		return "", err
	}

	nonceSize := s.gcm.NonceSize()
	if len(ciphertext) < nonceSize {
		return "", errors.New("ciphertext too short")
	}

	nonce, ciphertext := ciphertext[:nonceSize], ciphertext[nonceSize:]
	plaintext, err := s.gcm.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		return "", err
	}

	return string(plaintext), nil
}

func (s *SecureCredentialStore) StoreCredentials(username, apiKey, dbPassword, oauthSecret string) error {
	encAPIKey, err := s.encrypt(apiKey)
	if err != nil {
		return err
	}

	encDBPassword, err := s.encrypt(dbPassword)
	if err != nil {
		return err
	}

	encOAuthSecret, err := s.encrypt(oauthSecret)
	if err != nil {
		return err
	}

	query := `INSERT INTO user_credentials 
		(username, api_key_enc, db_password_enc, oauth_secret_enc) 
		VALUES ($1, $2, $3, $4)`

	_, err = s.db.Exec(query, username, encAPIKey, encDBPassword, encOAuthSecret)
	return err
}
