Excellent questions. Production systems need proper key rotation, envelope encryption for scalability, and integration with key management services (KMS). Here's a comprehensive production pattern:

**PRODUCTION PATTERN**:

```go
package secrets

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"database/sql"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"sync"
	"time"

	"github.com/aws/aws-sdk-go-v2/service/kms"
)

// EncryptedData contains encrypted payload with key metadata
type EncryptedData struct {
	KeyID      string `json:"key_id"`
	KeyVersion int    `json:"key_version"`
	Ciphertext string `json:"ciphertext"`
	EncryptedDEK string `json:"encrypted_dek"` // Data Encryption Key wrapped by KMS
	CreatedAt  time.Time `json:"created_at"`
}

// SecretManager handles encryption at rest with key rotation
type SecretManager struct {
	kmsClient    *kms.Client
	db           *sql.DB
	logger       *slog.Logger
	keyCache     map[string]*cachedKey
	cacheMutex   sync.RWMutex
	masterKeyARN string
}

type cachedKey struct {
	plaintextKey []byte
	expiresAt    time.Time
}

func NewSecretManager(kmsClient *kms.Client, db *sql.DB, masterKeyARN string, logger *slog.Logger) *SecretManager {
	return &SecretManager{
		kmsClient:    kmsClient,
		db:           db,
		logger:       logger,
		keyCache:     make(map[string]*cachedKey),
		masterKeyARN: masterKeyARN,
	}
}

// Encrypt uses envelope encryption: generate DEK, encrypt data, wrap DEK with KMS
func (sm *SecretManager) Encrypt(ctx context.Context, plaintext string, purpose string) (*EncryptedData, error) {
	// Generate a new Data Encryption Key (DEK) via KMS
	generateOutput, err := sm.kmsClient.GenerateDataKey(ctx, &kms.GenerateDataKeyInput{
		KeyId:   &sm.masterKeyARN,
		KeySpec: "AES_256",
		EncryptionContext: map[string]string{
			"purpose": purpose,
		},
	})
	if err != nil {
		sm.logger.Error("failed to generate data key",
			slog.String("error", err.Error()),
			slog.String("purpose", purpose))
		return nil, fmt.Errorf("failed to generate data key: %w", err)
	}

	// Encrypt the data with the plaintext DEK
	ciphertext, err := sm.encryptWithKey(generateOutput.Plaintext, []byte(plaintext))
	if err != nil {
		return nil, err
	}

	// Clear the plaintext key from memory
	for i := range generateOutput.Plaintext {
		generateOutput.Plaintext[i] = 0
	}

	sm.logger.Info("data encrypted successfully",
		slog.String("purpose", purpose),
		slog.String("key_id", *generateOutput.KeyId))

	return &EncryptedData{
		KeyID:        *generateOutput.KeyId,
		KeyVersion:   1,
		Ciphertext:   base64.StdEncoding.EncodeToString(ciphertext),
		EncryptedDEK: base64.StdEncoding.EncodeToString(generateOutput.CiphertextBlob),
		CreatedAt:    time.Now().UTC(),
	}, nil
}

// Decrypt unwraps DEK via KMS then decrypts data
func (sm *SecretManager) Decrypt(ctx context.Context, data *EncryptedData, purpose string) (string, error) {
	// Decode the encrypted DEK
	encryptedDEK, err := base64.StdEncoding.DecodeString(data.EncryptedDEK)
	if err != nil {
		return "", fmt.Errorf("invalid encrypted DEK: %w", err)
	}

	// Decrypt the DEK using KMS (with caching for performance)
	plaintextDEK, err := sm.decryptDEK(ctx, encryptedDEK, purpose)
	if err != nil {
		return "", err
	}
	defer func() {
		for i := range plaintextDEK {
			plaintextDEK[i] = 0
		}
	}()

	// Decode and decrypt the ciphertext
	ciphertext, err := base64.StdEncoding.DecodeString(data.Ciphertext)
	if err != nil {
		return "", fmt.Errorf("invalid ciphertext: %w", err)
	}

	plaintext, err := sm.decryptWithKey(plaintextDEK, ciphertext)
	if err != nil {
		sm.logger.Warn("decryption failed",
			slog.String("key_id", data.KeyID),
			slog.String("purpose", purpose))
		return "", err
	}

	return string(plaintext), nil
}

func (sm *SecretManager) decryptDEK(ctx context.Context, encryptedDEK []byte, purpose string) ([]byte, error) {
	// Check cache first
	cacheKey := base64.StdEncoding.EncodeToString(encryptedDEK)
	sm.cacheMutex.RLock()
	if cached, ok := sm.keyCache[cacheKey]; ok && time.Now().Before(cached.expiresAt) {
		sm.cacheMutex.RUnlock()
		return cached.plaintextKey, nil
	}
	sm.cacheMutex.RUnlock()

	// Decrypt DEK via KMS
	decryptOutput, err := sm.kmsClient.Decrypt(ctx, &kms.DecryptInput{
		CiphertextBlob: encryptedDEK,
		EncryptionContext: map[string]string{
			"purpose": purpose,
		},
	})
	if err != nil {
		return nil, fmt.Errorf("failed to decrypt DEK: %w", err)
	}

	// Cache the decrypted DEK for 5 minutes
	sm.cacheMutex.Lock()
	sm.keyCache[cacheKey] = &cachedKey{
		plaintextKey: decryptOutput.Plaintext,
		expiresAt:    time.Now().Add(5 * time.Minute),
	}
	sm.cacheMutex.Unlock()

	return decryptOutput.Plaintext, nil
}

func (sm *SecretManager) encryptWithKey(key, plaintext []byte) ([]byte, error) {
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, err
	}

	return gcm.Seal(nonce, nonce, plaintext, nil), nil
}

func (sm *SecretManager) decryptWithKey(key, ciphertext []byte) ([]byte, error) {
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonceSize := gcm.NonceSize()
	if len(ciphertext) < nonceSize {
		return nil, errors.New("ciphertext too short")
	}

	nonce, ciphertext := ciphertext[:nonceSize], ciphertext[nonceSize:]
	return gcm.Open(nil, nonce, ciphertext, nil)
}

// RotateSecrets re-encrypts all secrets with new keys (run periodically)
func (sm *SecretManager) RotateSecrets(ctx context.Context) error {
	sm.logger.Info("starting secret rotation")

	rows, err := sm.db.QueryContext(ctx, 
		`SELECT id, credential_type, encrypted_data FROM credentials 
		 WHERE encrypted_at < $1`, 
		time.Now().Add(-90*24*time.Hour)) // Rotate secrets older than 90 days
	if err != nil {
		return err
	}
	defer rows.Close()

	var rotated, failed int
	for rows.Next() {
		var id int
		var credType string
		var encryptedJSON []byte

		if err := rows.Scan(&id, &credType, &encryptedJSON); err != nil {
			failed++
			continue
		}

		var oldData EncryptedData
		if err := json.Unmarshal(encryptedJSON, &oldData); err != nil {
			failed++
			continue
		}

		// Decrypt with old key
		plaintext, err := sm.Decrypt(ctx, &oldData, credType)
		if err != nil {
			failed++
			sm.logger.Error("failed to decrypt for rotation",
				slog.Int("id", id),
				slog.String("error", err.Error()))
			continue
		}

		// Re-encrypt with new key
		newData, err := sm.Encrypt(ctx, plaintext, credType)
		if err != nil {
			failed++
			continue
		}

		newJSON, err := json.Marshal(newData)
		if err != nil {
			failed++
			continue
		}

		_, err = sm.db.ExecContext(ctx,
			`UPDATE credentials SET encrypted_data = $1, encrypted_at = $2 WHERE id = $3`,
			newJSON, time.Now().UTC(), id)
		if err != nil {
			failed++
		} else {
			rotated++
		}
	}

	sm.logger.Info("secret rotation completed",
		slog.Int("rotated", rotated),
		slog.Int("failed", failed))

	return nil
}
```

**Defense in Depth Layers**:

1. **Envelope Encryption**: Data encrypted with a Data Encryption Key (DEK), DEK encrypted with master key in KMS. If database is stolen, attacker still needs KMS access:
```go
// Each secret has its own DEK
generateOutput, _ := kmsClient.GenerateDataKey(ctx, &kms.GenerateDataKeyInput{
    KeyId:   &masterKeyARN,
    KeySpec: "AES_256",
})
// Plaintext DEK encrypts data, encrypted DEK stored alongside
```

2. **Encryption Context Binding**: KMS enforces that the same context used for encryption must be provided for decryption, preventing key misuse:
```go
EncryptionContext: map[string]string{
    "purpose": purpose,  // "api_key", "oauth_secret", etc.
}
```

3. **Memory Protection**: Plaintext keys are zeroed after use to minimize exposure window:
```go
defer func() {
    for i := range plaintextDEK {
        plaintextDEK[i] = 0
    }
}()
```

**Additional Protections**:
- **Automatic key rotation**: AWS KMS supports automatic annual key rotation; this code handles re-encryption of existing data
- **Audit logging**: All encryption/decryption operations logged with structured logging for SIEM integration
- **DEK caching**: Reduces KMS API calls while maintaining security (5-minute cache with automatic invalidation)
- **Purpose separation**: Different credential types use different encryption contexts, providing key isolation
- **Gradual rotation**: Batch rotation with error handling prevents all-or-nothing failures
- **Timestamp tracking**: `encrypted_at` column enables compliance reporting and rotation scheduling

