using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.Security.KeyVault.Keys;
using Azure.Security.KeyVault.Keys.Cryptography;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;

namespace SecureApp.Services
{
    public interface IEncryptionService
    {
        Task<EncryptedData> EncryptAsync(string plaintext, DataClassification classification);
        Task<string> DecryptAsync(EncryptedData encryptedData);
    }

    public enum DataClassification
    {
        PII,           // Names, addresses, phone numbers
        PHI,           // Health records (HIPAA)
        PCI,           // Payment card data
        Confidential   // Internal sensitive data
    }

    public class EncryptedData
    {
        public string Ciphertext { get; set; }
        public string KeyId { get; set; }
        public string IV { get; set; }
        public string AuthTag { get; set; }
        public int KeyVersion { get; set; }
        public DateTime EncryptedAt { get; set; }
    }

    public class AzureKeyVaultEncryptionService : IEncryptionService
    {
        private readonly KeyClient _keyClient;
        private readonly IMemoryCache _cache;
        private readonly ILogger<AzureKeyVaultEncryptionService> _logger;
        private readonly Dictionary<DataClassification, string> _keyMapping;

        public AzureKeyVaultEncryptionService(
            IConfiguration config,
            IMemoryCache cache,
            ILogger<AzureKeyVaultEncryptionService> logger)
        {
            var keyVaultUrl = config["Azure:KeyVaultUrl"];
            _keyClient = new KeyClient(
                new Uri(keyVaultUrl),
                new DefaultAzureCredential());
            _cache = cache;
            _logger = logger;

            // Different keys for different data classifications
            _keyMapping = new Dictionary<DataClassification, string>
            {
                { DataClassification.PII, "pii-encryption-key" },
                { DataClassification.PHI, "phi-encryption-key" },
                { DataClassification.PCI, "pci-encryption-key" },
                { DataClassification.Confidential, "conf-encryption-key" }
            };
        }

        public async Task<EncryptedData> EncryptAsync(string plaintext, DataClassification classification)
        {
            if (string.IsNullOrEmpty(plaintext))
                throw new ArgumentException("Plaintext cannot be empty");

            string keyName = _keyMapping[classification];

            try
            {
                // Get or cache the key
                var key = await GetOrCacheKeyAsync(keyName);
                var cryptoClient = new CryptographyClient(key.Id, new DefaultAzureCredential());

                // Generate random IV for AES-GCM
                byte[] iv = new byte[12];
                using (var rng = RandomNumberGenerator.Create())
                {
                    rng.GetBytes(iv);
                }

                // Encrypt using AES-GCM (authenticated encryption)
                byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
                byte[] ciphertext = new byte[plaintextBytes.Length];
                byte[] authTag = new byte[16];

                using (var aesGcm = new AesGcm(await GetDataEncryptionKeyAsync(cryptoClient)))
                {
                    aesGcm.Encrypt(iv, plaintextBytes, ciphertext, authTag);
                }

                _logger.LogInformation(
                    "Encrypted {Classification} data with key {KeyName} version {Version}",
                    classification, keyName, key.Properties.Version);

                return new EncryptedData
                {
                    Ciphertext = Convert.ToBase64String(ciphertext),
                    KeyId = keyName,
                    IV = Convert.ToBase64String(iv),
                    AuthTag = Convert.ToBase64String(authTag),
                    KeyVersion = int.Parse(key.Properties.Version ?? "1"),
                    EncryptedAt = DateTime.UtcNow
                };
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Encryption failed for {Classification} data", classification);
                throw new CryptographicException("Encryption operation failed", ex);
            }
        }

        public async Task<string> DecryptAsync(EncryptedData encryptedData)
        {
            if (encryptedData == null)
                throw new ArgumentNullException(nameof(encryptedData));

            try
            {
                var key = await GetOrCacheKeyAsync(encryptedData.KeyId);
                var cryptoClient = new CryptographyClient(key.Id, new DefaultAzureCredential());

                byte[] iv = Convert.FromBase64String(encryptedData.IV);
                byte[] ciphertext = Convert.FromBase64String(encryptedData.Ciphertext);
                byte[] authTag = Convert.FromBase64String(encryptedData.AuthTag);
                byte[] plaintext = new byte[ciphertext.Length];

                using (var aesGcm = new AesGcm(await GetDataEncryptionKeyAsync(cryptoClient)))
                {
                    aesGcm.Decrypt(iv, ciphertext, authTag, plaintext);
                }

                _logger.LogInformation(
                    "Decrypted data with key {KeyId}", encryptedData.KeyId);

                return Encoding.UTF8.GetString(plaintext);
            }
            catch (AuthenticationTagMismatchException)
            {
                _logger.LogWarning("Authentication tag mismatch - possible tampering detected");
                throw new CryptographicException("Data integrity check failed");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Decryption failed for key {KeyId}", encryptedData.KeyId);
                throw new CryptographicException("Decryption operation failed", ex);
            }
        }

        private async Task<KeyVaultKey> GetOrCacheKeyAsync(string keyName)
        {
            string cacheKey = $"key_{keyName}";

            if (!_cache.TryGetValue(cacheKey, out KeyVaultKey key))
            {
                key = await _keyClient.GetKeyAsync(keyName);
                _cache.Set(cacheKey, key, TimeSpan.FromMinutes(15));
            }

            return key;
        }

        private async Task<byte[]> GetDataEncryptionKeyAsync(CryptographyClient client)
        {
            // Generate a random DEK and wrap it with the KEK (envelope encryption)
            byte[] dek = new byte[32];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(dek);
            }
            return dek;
        }
    }
}
