        {
            // Configure encrypted columns
            foreach (var entityType in modelBuilder.Model.GetEntityTypes())
            {
                foreach (var property in entityType.GetProperties())
                {
                    var attributes = property.PropertyInfo?
                        .GetCustomAttributes(typeof(EncryptedAttribute), false);

                    if (attributes?.Length > 0)
                    {
                        var encAttr = (EncryptedAttribute)attributes[0];

                        // Store as JSON containing encrypted data
                        property.SetValueConverter(
                            new ValueConverter<string, string>(
                                v => EncryptValue(v, encAttr.Classification),
                                v => DecryptValue(v)
                            ));

                        // Increase column size for encrypted data
                        property.SetMaxLength(4000);
                    }
                }
            }
        }

        private string EncryptValue(string value, DataClassification classification)
        {
            if (string.IsNullOrEmpty(value)) return value;
            var encrypted = _encryptionService.EncryptAsync(value, classification).Result;
            return System.Text.Json.JsonSerializer.Serialize(encrypted);
        }

        private string DecryptValue(string value)
        {
            if (string.IsNullOrEmpty(value)) return value;
            var encrypted = System.Text.Json.JsonSerializer.Deserialize<EncryptedData>(value);
            return _encryptionService.DecryptAsync(encrypted).Result;
        }
    }
