```csharp
public class EnvelopeEncryption
{
    // Key Encryption Key (KEK) - stored in HSM/Key Vault
    // Data Encryption Key (DEK) - generated per record/session

    public async Task<(byte[] EncryptedDEK, byte[] EncryptedData)> EncryptWithEnvelope(
        byte[] data, CryptographyClient kekClient)
    {
        // Generate random DEK
        byte[] dek = new byte[32];
        RandomNumberGenerator.Fill(dek);

        // Wrap DEK with KEK (stored in Key Vault)
        var wrappedKey = await kekClient.WrapKeyAsync(
            KeyWrapAlgorithm.RsaOaep256, dek);

        // Encrypt data with DEK locally (faster)
        byte[] encryptedData = EncryptWithAesGcm(data, dek);

        // Clear DEK from memory
        Array.Clear(dek, 0, dek.Length);

        return (wrappedKey.EncryptedKey, encryptedData);
    }
}
