**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const crypto = require('crypto');
const { KMSClient, DecryptCommand, GenerateDataKeyCommand } = require('@aws-sdk/client-kms');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production logging with security context
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// AWS KMS client for key management
const kmsClient = new KMSClient({ region: process.env.AWS_REGION });
const KMS_KEY_ID = process.env.KMS_KEY_ARN;

class EncryptionService {
  constructor() {
    this.keyCache = new Map();
    this.ALGORITHM = 'aes-256-gcm';
    this.KEY_VERSION_HEADER = 'v2'; // Track key versions for rotation
  }

  // Generate a new Data Encryption Key (DEK) using envelope encryption
  async generateDataKey() {
    const command = new GenerateDataKeyCommand({
      KeyId: KMS_KEY_ID,
      KeySpec: 'AES_256'
    });

    const response = await kmsClient.send(command);

    return {
      plaintext: response.Plaintext,                    // Use for encryption
      ciphertext: response.CiphertextBlob.toString('base64') // Store this
    };
  }

  // Decrypt a DEK using KMS
  async decryptDataKey(encryptedKey) {
    // Check cache first to reduce KMS calls
    const cacheKey = encryptedKey.slice(0, 32);
    if (this.keyCache.has(cacheKey)) {
      return this.keyCache.get(cacheKey);
    }

    const command = new DecryptCommand({
      CiphertextBlob: Buffer.from(encryptedKey, 'base64'),
      KeyId: KMS_KEY_ID
    });

    const response = await kmsClient.send(command);

    // Cache with TTL (clear after 5 minutes)
    this.keyCache.set(cacheKey, response.Plaintext);
    setTimeout(() => this.keyCache.delete(cacheKey), 5 * 60 * 1000);

    return response.Plaintext;
  }

  // Encrypt with envelope encryption pattern
  async encrypt(plaintext, existingEncryptedDEK = null) {
    let dek, encryptedDEK;

    if (existingEncryptedDEK) {
      dek = await this.decryptDataKey(existingEncryptedDEK);
      encryptedDEK = existingEncryptedDEK;
    } else {
      const keyPair = await this.generateDataKey();
      dek = keyPair.plaintext;
      encryptedDEK = keyPair.ciphertext;
    }

    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv(this.ALGORITHM, dek, iv);

    let encrypted = cipher.update(plaintext, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();

    // Format: VERSION:ENCRYPTED_DEK:IV:AUTHTAG:CIPHERTEXT
    return `${this.KEY_VERSION_HEADER}:${encryptedDEK}:${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted}`;
  }

  async decrypt(encryptedData) {
    const parts = encryptedData.split(':');
    const version = parts[0];
    const encryptedDEK = parts[1];
    const iv = Buffer.from(parts[2], 'hex');
    const authTag = Buffer.from(parts[3], 'hex');
    const ciphertext = parts[4];

    // Handle different key versions for rotation compatibility
    if (version !== this.KEY_VERSION_HEADER) {
      logger.warn('Decrypting data with old key version', { version });
    }

    const dek = await this.decryptDataKey(encryptedDEK);

    const decipher = crypto.createDecipheriv(this.ALGORITHM, dek, iv);
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(ciphertext, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }
}

const encryptionService = new EncryptionService();

// Schema with key rotation support
const PaymentSchema = new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  encryptedCardNumber: String,
  cardLastFour: String,
  encryptedExpiry: String,
  encryptedCardholderName: String,
  encryptedBillingAddress: String,
  cardFingerprint: String,
  keyVersion: { type: String, default: 'v2' },  // Track encryption key version
  needsReEncryption: { type: Boolean, default: false },
  createdAt: { type: Date, default: Date.now },
  lastAccessedAt: Date
});

const Payment = mongoose.model('Payment', PaymentSchema);

// Key rotation job - re-encrypts records with old key versions
class KeyRotationService {
  async rotateKeys(batchSize = 100) {
    const oldRecords = await Payment.find({ 
      $or: [
        { keyVersion: { $ne: 'v2' } },
        { needsReEncryption: true }
      ]
    }).limit(batchSize);

    let rotatedCount = 0;

    for (const record of oldRecords) {
      try {
        // Decrypt with old key
        const cardNumber = await encryptionService.decrypt(record.encryptedCardNumber);
        const expiry = await encryptionService.decrypt(record.encryptedExpiry);
        const name = await encryptionService.decrypt(record.encryptedCardholderName);
        const address = await encryptionService.decrypt(record.encryptedBillingAddress);

        // Re-encrypt with new DEK
        record.encryptedCardNumber = await encryptionService.encrypt(cardNumber);
        record.encryptedExpiry = await encryptionService.encrypt(expiry);
        record.encryptedCardholderName = await encryptionService.encrypt(name);
        record.encryptedBillingAddress = await encryptionService.encrypt(address);
        record.keyVersion = 'v2';
        record.needsReEncryption = false;

        await record.save();
        rotatedCount++;

        logger.info('Key rotation completed for record', { 
          paymentId: record._id,
          userId: record.userId 
        });
      } catch (error) {
        logger.error('Key rotation failed for record', { 
          paymentId: record._id, 
          error: error.message 
        });
      }
    }

    return { rotated: rotatedCount, remaining: oldRecords.length - rotatedCount };
  }
}

const keyRotationService = new KeyRotationService();

// API endpoints
app.post('/api/payments/add-card', async (req, res) => {
  const startTime = Date.now();

