import javax.crypto.Cipher;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.sql.*;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import com.amazonaws.services.kms.AWSKMS;
import com.amazonaws.services.kms.AWSKMSClientBuilder;
import com.amazonaws.services.kms.model.*;

public class ProductionPaymentService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionPaymentService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;
    private static final int DEK_KEY_LENGTH = 32;  // 256 bits

    private final AWSKMS kmsClient;
    private final String masterKeyId;  // KMS Customer Master Key ARN
    private final SecureRandom secureRandom;
    private final ConcurrentHashMap<String, CachedDEK> dekCache;
    private final DataSource dataSource;

    public ProductionPaymentService(DataSource dataSource, String kmsKeyArn) {
        this.dataSource = dataSource;
        this.masterKeyId = kmsKeyArn;
        this.kmsClient = AWSKMSClientBuilder.defaultClient();
        this.secureRandom = new SecureRandom();
        this.dekCache = new ConcurrentHashMap<>();
    }

    /**
     * Envelope Encryption: Generate a new Data Encryption Key (DEK) 
     * encrypted by the Master Key (KEK) stored in KMS/HSM
     */
    private EncryptedDEK generateDataEncryptionKey() {
        GenerateDataKeyRequest request = new GenerateDataKeyRequest()
            .withKeyId(masterKeyId)
            .withKeySpec(DataKeySpec.AES_256);

        GenerateDataKeyResult result = kmsClient.generateDataKey(request);

        byte[] plaintextKey = result.getPlaintext().array();
        byte[] encryptedKey = result.getCiphertextBlob().array();
        String keyId = generateKeyId();

        return new EncryptedDEK(keyId, plaintextKey, encryptedKey);
    }

    /**
     * Decrypt DEK using KMS when needed (with caching for performance)
     */
    private SecretKey decryptDataEncryptionKey(byte[] encryptedDEK, String keyId) {
        // Check cache first (DEKs cached for 5 minutes max)
        CachedDEK cached = dekCache.get(keyId);
        if (cached != null && !cached.isExpired()) {
            return cached.getKey();
        }

        DecryptRequest request = new DecryptRequest()
            .withCiphertextBlob(java.nio.ByteBuffer.wrap(encryptedDEK))
            .withKeyId(masterKeyId);

        DecryptResult result = kmsClient.decrypt(request);
        byte[] plaintextKey = result.getPlaintext().array();

        SecretKey dek = new SecretKeySpec(plaintextKey, "AES");

        // Cache with expiration
        dekCache.put(keyId, new CachedDEK(dek, System.currentTimeMillis() + 300000));

        // Clear plaintext from memory
        java.util.Arrays.fill(plaintextKey, (byte) 0);

        return dek;
    }

    public String savePaymentMethod(int customerId, String cardNumber, 
                                     String cardHolder, String expiry,
                                     String requestId, String userAgent) {
        // Input validation
        validateCardNumber(cardNumber);
        validateCustomerId(customerId);

        // Generate new DEK for this record (key-per-record for isolation)
        EncryptedDEK dek = generateDataEncryptionKey();

        try {
            // Encrypt with DEK
            EncryptedData encryptedCard = encryptWithDEK(cardNumber, dek.getPlaintextKey());
            EncryptedData encryptedHolder = encryptWithDEK(cardHolder, dek.getPlaintextKey());
            String maskedCard = maskCardNumber(cardNumber);
            String paymentMethodId = generateSecureId();

            String sql = "INSERT INTO payment_methods (id, customer_id, encrypted_card, " +
                         "card_iv, encrypted_holder, holder_iv, expiry_date, card_mask, " +
                         "encrypted_dek, dek_key_id, key_version, created_at) " +
                         "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW())";

            try (Connection conn = dataSource.getConnection();
                 PreparedStatement stmt = conn.prepareStatement(sql)) {

                stmt.setString(1, paymentMethodId);
                stmt.setInt(2, customerId);
                stmt.setBytes(3, encryptedCard.getCiphertext());
                stmt.setBytes(4, encryptedCard.getIv());
                stmt.setBytes(5, encryptedHolder.getCiphertext());
                stmt.setBytes(6, encryptedHolder.getIv());
                stmt.setString(7, expiry);
                stmt.setString(8, maskedCard);
                stmt.setBytes(9, dek.getEncryptedKey());  // Store encrypted DEK
                stmt.setString(10, dek.getKeyId());
                stmt.setInt(11, getCurrentKeyVersion());
                stmt.executeUpdate();
            }

            // Audit log (no sensitive data)
            auditLogger.info("PAYMENT_METHOD_CREATED|customer={}|method={}|mask={}|" +
                           "requestId={}|keyVersion={}", 
                           customerId, paymentMethodId, maskedCard, 
                           requestId, getCurrentKeyVersion());

            return paymentMethodId;

        } finally {
            // CRITICAL: Clear plaintext key from memory
            dek.clearPlaintextKey();
        }
