    public String getDecryptedCardNumber(String paymentMethodId, int customerId,
                                          String requestId, String purpose) {
        // Validate purpose - only allow specific use cases
        if (!isValidDecryptionPurpose(purpose)) {
            auditLogger.warn("DECRYPT_DENIED|method={}|customer={}|purpose={}|requestId={}",
                           paymentMethodId, customerId, purpose, requestId);
            throw new SecurityException("Invalid decryption purpose");
        }

        String sql = "SELECT encrypted_card, card_iv, encrypted_dek, dek_key_id, customer_id " +
                     "FROM payment_methods WHERE id = ?";

        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement(sql)) {

            stmt.setString(1, paymentMethodId);
            ResultSet rs = stmt.executeQuery();

            if (!rs.next()) {
                throw new PaymentNotFoundException("Payment method not found");
            }

            // Verify customer ownership
            if (rs.getInt("customer_id") != customerId) {
                auditLogger.warn("DECRYPT_UNAUTHORIZED|method={}|requestedBy={}|owner={}|requestId={}",
                               paymentMethodId, customerId, rs.getInt("customer_id"), requestId);
                throw new SecurityException("Unauthorized access attempt");
            }

            byte[] encryptedCard = rs.getBytes("encrypted_card");
            byte[] iv = rs.getBytes("card_iv");
            byte[] encryptedDEK = rs.getBytes("encrypted_dek");
            String keyId = rs.getString("dek_key_id");

            // Decrypt DEK using KMS
            SecretKey dek = decryptDataEncryptionKey(encryptedDEK, keyId);

            // Decrypt card number
            String cardNumber = decryptWithDEK(encryptedCard, iv, dek);

            // Audit successful decryption
            auditLogger.info("CARD_DECRYPTED|method={}|customer={}|purpose={}|requestId={}",
                           paymentMethodId, customerId, purpose, requestId);

            return cardNumber;

        } catch (SQLException e) {
            logger.error("Database error retrieving payment method", e);
            throw new PaymentServiceException("Failed to retrieve payment method");
        }
    }

    private EncryptedData encryptWithDEK(String plaintext, byte[] keyBytes) {
        try {
            byte[] iv = new byte[GCM_IV_LENGTH];
            secureRandom.nextBytes(iv);

            SecretKey key = new SecretKeySpec(keyBytes, "AES");
            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.ENCRYPT_MODE, key, spec);

            byte[] ciphertext = cipher.doFinal(plaintext.getBytes("UTF-8"));

            return new EncryptedData(ciphertext, iv);
        } catch (Exception e) {
            throw new SecurityException("Encryption failed", e);
        }
    }

    private String decryptWithDEK(byte[] ciphertext, byte[] iv, SecretKey key) {
        try {
            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.DECRYPT_MODE, key, spec);

            byte[] plaintext = cipher.doFinal(ciphertext);
            return new String(plaintext, "UTF-8");
        } catch (Exception e) {
            logger.error("Decryption failed - possible tampering", e);
            throw new SecurityException("Decryption failed");
        }
    }

    /**
     * Key rotation: Re-encrypt all records with new DEKs
     */
    public void rotateKeys(String batchId) {
        auditLogger.info("KEY_ROTATION_STARTED|batch={}", batchId);

        String selectSql = "SELECT id FROM payment_methods WHERE key_version < ?";
        int currentVersion = getCurrentKeyVersion();

        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement(selectSql)) {

            stmt.setInt(1, currentVersion);
            ResultSet rs = stmt.executeQuery();

            int rotated = 0;
            while (rs.next()) {
                rotateKeyForRecord(rs.getString("id"), currentVersion);
                rotated++;
            }

            auditLogger.info("KEY_ROTATION_COMPLETED|batch={}|records={}", batchId, rotated);

        } catch (SQLException e) {
            auditLogger.error("KEY_ROTATION_FAILED|batch={}", batchId, e);
            throw new PaymentServiceException("Key rotation failed");
        }
    }

    private void validateCardNumber(String cardNumber) {
        if (cardNumber == null || !cardNumber.matches("^\\d{13,19}$")) {
            throw new IllegalArgumentException("Invalid card number format");
        }
        if (!passesLuhnCheck(cardNumber)) {
            throw new IllegalArgumentException("Invalid card number");
        }
    }

    private boolean passesLuhnCheck(String cardNumber) {
        int sum = 0;
        boolean alternate = false;
        for (int i = cardNumber.length() - 1; i >= 0; i--) {
            int digit = Character.getNumericValue(cardNumber.charAt(i));
            if (alternate) {
                digit *= 2;
                if (digit > 9) digit -= 9;
            }
            sum += digit;
            alternate = !alternate;
        }
        return sum % 10 == 0;
    }

    private String maskCardNumber(String cardNumber) {
        int len = cardNumber.length();
        return "*".repeat(len - 4) + cardNumber.substring(len - 4);
    }

    private String generateSecureId() {
        byte[] bytes = new byte[16];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private String generateKeyId() {
        return "dek-" + System.currentTimeMillis() + "-" + generateSecureId().substring(0, 8);
    }

    private int getCurrentKeyVersion() {
        return Integer.parseInt(System.getenv().getOrDefault("ENCRYPTION_KEY_VERSION", "1"));
    }

    private boolean isValidDecryptionPurpose(String purpose) {
        return purpose != null && 
               (purpose.equals("PAYMENT_PROCESSING") || 
                purpose.equals("FRAUD_INVESTIGATION") ||
                purpose.equals("CUSTOMER_SUPPORT_VERIFIED"));
    }

    // Helper classes
    private static class EncryptedDEK {
        private final String keyId;
        private byte[] plaintextKey;
        private final byte[] encryptedKey;

        EncryptedDEK(String keyId, byte[] plaintextKey, byte[] encryptedKey) {
            this.keyId = keyId;
            this.plaintextKey = plaintextKey.clone();
            this.encryptedKey = encryptedKey.clone();
        }

        String getKeyId() { return keyId; }
        byte[] getPlaintextKey() { return plaintextKey; }
        byte[] getEncryptedKey() { return encryptedKey; }

        void clearPlaintextKey() {
            if (plaintextKey != null) {
                java.util.Arrays.fill(plaintextKey, (byte) 0);
                plaintextKey = null;
            }
        }
    }

    private static class EncryptedData {
        private final byte[] ciphertext;
        private final byte[] iv;

        EncryptedData(byte[] ciphertext, byte[] iv) {
            this.ciphertext = ciphertext;
            this.iv = iv;
        }

        byte[] getCiphertext() { return ciphertext; }
        byte[] getIv() { return iv; }
    }

    private static class CachedDEK {
        private final SecretKey key;
        private final long expiresAt;

        CachedDEK(SecretKey key, long expiresAt) {
            this.key = key;
            this.expiresAt = expiresAt;
        }

        SecretKey getKey() { return key; }
        boolean isExpired() { return System.currentTimeMillis() > expiresAt; }
    }
}
