```go
package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
)

type UserData struct {
	Username    string `json:"username"`
	Email       string `json:"email"`
	SSN         string `json:"ssn"`
	CreditCard  string `json:"credit_card"`
	PasswordHash string `json:"password_hash"` // Store hash, not plaintext
}

func encryptData(plaintext, key []byte) ([]byte, error) {
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, err
	}

	// Nonce is prepended to ciphertext for storage
	return gcm.Seal(nonce, nonce, plaintext, nil), nil
}

func decryptData(ciphertext, key []byte) ([]byte, error) {
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonceSize := gcm.NonceSize()
	if len(ciphertext) < nonceSize {
		return nil, errors.New("ciphertext too short")
	}

	nonce, ciphertext := ciphertext[:nonceSize], ciphertext[nonceSize:]
	return gcm.Open(nil, nonce, ciphertext, nil)
}

func saveUserDataSecure(user UserData, filename string, key []byte) error {
	data, err := json.Marshal(user)
	if err != nil {
		return fmt.Errorf("failed to marshal user data: %w", err)
	}

	encrypted, err := encryptData(data, key)
	if err != nil {
		return fmt.Errorf("failed to encrypt data: %w", err)
	}

	// Restrictive permissions: only owner can read/write
	return os.WriteFile(filename, encrypted, 0600)
}

func loadUserDataSecure(filename string, key []byte) (UserData, error) {
	var user UserData

	encrypted, err := os.ReadFile(filename)
	if err != nil {
		return user, fmt.Errorf("failed to read file: %w", err)
	}

	data, err := decryptData(encrypted, key)
	if err != nil {
		return user, fmt.Errorf("failed to decrypt data: %w", err)
	}

	if err := json.Unmarshal(data, &user); err != nil {
		return user, fmt.Errorf("failed to unmarshal user data: %w", err)
	}

	return user, nil
}
```

**Key Security Controls**:
- **AES-256-GCM encryption**: Industry-standard authenticated encryption that provides confidentiality and integrity
- **Random nonce generation**: Uses cryptographically secure random nonces to prevent IV reuse attacks
- **Restrictive file permissions**: 0600 ensures only the owner can read/write the file
- **Password hashing**: Passwords should be hashed with bcrypt/argon2, never stored even encrypted

