**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"os"
	"time"

	"github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/service/kms"
)

// EncryptedEnvelope stores encrypted data with its encrypted DEK
type EncryptedEnvelope struct {
	EncryptedDEK []byte `json:"encrypted_dek"` // Data Encryption Key wrapped by KMS
	Ciphertext   []byte `json:"ciphertext"`    // Data encrypted with DEK
	KeyID        string `json:"key_id"`        // KMS Key ARN for rotation tracking
	Timestamp    int64  `json:"timestamp"`     // Encryption timestamp for audit
}

// SecureStorage handles encryption at rest with proper key management
type SecureStorage struct {
	kmsClient    *kms.Client
	masterKeyARN string
	auditLogger  *log.Logger
}

func NewSecureStorage(masterKeyARN string) (*SecureStorage, error) {
	cfg, err := config.LoadDefaultConfig(context.Background())
	if err != nil {
		return nil, fmt.Errorf("failed to load AWS config: %w", err)
	}

	auditLogger := log.New(os.Stdout, "[AUDIT] ", log.LstdFlags|log.LUTC)

	return &SecureStorage{
		kmsClient:    kms.NewFromConfig(cfg),
		masterKeyARN: masterKeyARN,
		auditLogger:  auditLogger,
	}, nil
}

// GenerateDataKey creates a new DEK using envelope encryption
func (s *SecureStorage) GenerateDataKey(ctx context.Context) ([]byte, []byte, error) {
	output, err := s.kmsClient.GenerateDataKey(ctx, &kms.GenerateDataKeyInput{
		KeyId:   &s.masterKeyARN,
		KeySpec: "AES_256",
	})
	if err != nil {
		s.auditLogger.Printf("FAILURE: GenerateDataKey failed for key %s: %v", s.masterKeyARN, err)
		return nil, nil, fmt.Errorf("failed to generate data key: %w", err)
	}

	s.auditLogger.Printf("SUCCESS: Generated new DEK using master key %s", s.masterKeyARN)

	// Return plaintext DEK (for encryption) and encrypted DEK (for storage)
	return output.Plaintext, output.CiphertextBlob, nil
}

// DecryptDataKey unwraps an encrypted DEK using KMS
func (s *SecureStorage) DecryptDataKey(ctx context.Context, encryptedDEK []byte) ([]byte, error) {
	output, err := s.kmsClient.Decrypt(ctx, &kms.DecryptInput{
		CiphertextBlob: encryptedDEK,
		KeyId:          &s.masterKeyARN,
	})
	if err != nil {
		s.auditLogger.Printf("FAILURE: DecryptDataKey failed: %v", err)
		return nil, fmt.Errorf("failed to decrypt data key: %w", err)
	}

	s.auditLogger.Printf("SUCCESS: Decrypted DEK using master key %s", s.masterKeyARN)
	return output.Plaintext, nil
}

func (s *SecureStorage) encryptWithDEK(plaintext, dek []byte) ([]byte, error) {
	block, err := aes.NewCipher(dek)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, err
	}

	return gcm.Seal(nonce, nonce, plaintext, nil), nil
}

func (s *SecureStorage) decryptWithDEK(ciphertext, dek []byte) ([]byte, error) {
	block, err := aes.NewCipher(dek)
	if err != nil {
		return nil, err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonceSize := gcm.NonceSize()
	if len(ciphertext) < nonceSize {
		return nil, errors.New("ciphertext too short")
	}

	nonce, ciphertext := ciphertext[:nonceSize], ciphertext[nonceSize:]
	return gcm.Open(nil, nonce, ciphertext, nil)
}

// EncryptAndStore encrypts data using envelope encryption and saves to file
func (s *SecureStorage) EncryptAndStore(ctx context.Context, data []byte, filepath string) error {
	// Generate a unique DEK for this data
	plaintextDEK, encryptedDEK, err := s.GenerateDataKey(ctx)
	if err != nil {
		return err
	}

	// Encrypt data with the plaintext DEK
	ciphertext, err := s.encryptWithDEK(data, plaintextDEK)
	if err != nil {
		return fmt.Errorf("failed to encrypt data: %w", err)
	}

	// Zero out the plaintext DEK from memory immediately
	for i := range plaintextDEK {
		plaintextDEK[i] = 0
	}

	// Create envelope with encrypted DEK and ciphertext
	envelope := EncryptedEnvelope{
		EncryptedDEK: encryptedDEK,
		Ciphertext:   ciphertext,
		KeyID:        s.masterKeyARN,
		Timestamp:    time.Now().UTC().Unix(),
	}

	envelopeJSON, err := json.Marshal(envelope)
	if err != nil {
		return fmt.Errorf("failed to marshal envelope: %w", err)
	}

	// Write with restrictive permissions
	if err := os.WriteFile(filepath, envelopeJSON, 0600); err != nil {
		return fmt.Errorf("failed to write file: %w", err)
	}

	s.auditLogger.Printf("SUCCESS: Encrypted and stored data to %s", filepath)
	return nil
}

// LoadAndDecrypt reads encrypted envelope and decrypts data
func (s *SecureStorage) LoadAndDecrypt(ctx context.Context, filepath string) ([]byte, error) {
	envelopeJSON, err := os.ReadFile(filepath)
	if err != nil {
		s.auditLogger.Printf("FAILURE: Failed to read file %s: %v", filepath, err)
		return nil, fmt.Errorf("failed to read file: %w", err)
	}

	var envelope EncryptedEnvelope
	if err := json.Unmarshal(envelopeJSON, &envelope); err != nil {
		return nil, fmt.Errorf("failed to unmarshal envelope: %w", err)
	}

	// Decrypt the DEK using KMS
	plaintextDEK, err := s.DecryptDataKey(ctx, envelope.EncryptedDEK)
	if err != nil {
		return nil, err
	}

	// Decrypt the data using the plaintext DEK
	plaintext, err := s.decryptWithDEK(envelope.Ciphertext, plaintextDEK)

	// Zero out the plaintext DEK from memory immediately
	for i := range plaintextDEK {
		plaintextDEK[i] = 0
	}

	if err != nil {
		s.auditLogger.Printf("FAILURE: Decryption failed for %s: %v", filepath, err)
		return nil, fmt.Errorf("failed to decrypt data: %w", err)
	}

	s.auditLogger.Printf("SUCCESS: Decrypted data from %s", filepath)
	return plaintext, nil
}

// Key rotation support - re-encrypt with new key
func (s *SecureStorage) RotateKey(ctx context.Context, filepath string, newKeyARN string) error {
	// Decrypt with current key
	plaintext, err := s.LoadAndDecrypt(ctx, filepath)
	if err != nil {
		return fmt.Errorf("rotation failed - decrypt error: %w", err)
	}

	// Update to new master key
	oldKeyARN := s.masterKeyARN
	s.masterKeyARN = newKeyARN

	// Re-encrypt with new key
	if err := s.EncryptAndStore(ctx, plaintext, filepath); err != nil {
		s.masterKeyARN = oldKeyARN // Rollback on failure
		return fmt.Errorf("rotation failed - encrypt error: %w", err)
	}

	s.auditLogger.Printf("SUCCESS: Rotated key from %s to %s for %s", oldKeyARN, newKeyARN, filepath)
	return nil
}
```

**Defense in Depth Layers**:

1. **Envelope Encryption**: 
```go
// Data is encrypted with a unique DEK, DEK is encrypted with master key in KMS
// Even if attacker gets the encrypted file, they need KMS access to decrypt
plaintextDEK, encryptedDEK, _ := s.GenerateDataKey(ctx)
ciphertext := encryptWithDEK(data, plaintextDEK)
// Store: {encrypted_dek, ciphertext} - both useless without KMS access
```

2. **Memory Protection**:
```go
// Zero out plaintext keys from memory immediately after use
for i := range plaintextDEK {
    plaintextDEK[i] = 0
}
// Reduces window for memory-scraping attacks
```

3. **Audit Logging**:
```go
// Every encryption/decryption operation is logged
s.auditLogger.Printf("SUCCESS: Decrypted DEK using master key %s", s.masterKeyARN)
// Enables detection of unauthorized access attempts
```

**Additional Protections**:

- **Key rotation support**: RotateKey() allows periodic key rotation without data loss, essential for compliance
- **Unique DEK per file**: Each file gets its own DEK, limiting blast radius if any single DEK is compromised
- **IAM-based access control**: KMS access controlled through AWS IAM policies, not application code
- **Hardware Security Module (HSM)**: KMS master keys never leave HSM in plaintext, providing FIPS 140-2 compliance
- **File permissions**: 0600 ensures only owner can access encrypted files on disk
- **Timestamp tracking**: Enables forensics and compliance audits for when data was encrypted

