Storing sensitive data like credit card numbers in plaintext is extremely dangerous and violates PCI-DSS compliance requirements. If your database is compromised, attackers get immediate access to all payment data.

**VULNERABLE CODE**:

```csharp
using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;

namespace PaymentApp.Controllers
{
    public class PaymentController : ControllerBase
    {
        private readonly string _connectionString;

        public PaymentController(IConfiguration config)
        {
            _connectionString = config.GetConnectionString("DefaultConnection");
        }

        [HttpPost("api/payments/save-card")]
        public IActionResult SaveCreditCard([FromBody] CardRequest request)
        {
            // VULNERABLE: Storing credit card in plaintext!
            using (var connection = new SqlConnection(_connectionString))
            {
                connection.Open();
                var sql = @"INSERT INTO PaymentMethods 
                           (UserId, CardNumber, CVV, ExpiryDate, CardholderName) 
                           VALUES (@UserId, @CardNumber, @CVV, @Expiry, @Name)";

                using (var cmd = new SqlCommand(sql, connection))
                {
                    cmd.Parameters.AddWithValue("@UserId", request.UserId);
                    cmd.Parameters.AddWithValue("@CardNumber", request.CardNumber);  // Plaintext!
                    cmd.Parameters.AddWithValue("@CVV", request.CVV);                 // Plaintext!
                    cmd.Parameters.AddWithValue("@Expiry", request.ExpiryDate);
                    cmd.Parameters.AddWithValue("@Name", request.CardholderName);
                    cmd.ExecuteNonQuery();
                }
            }
            return Ok(new { message = "Card saved successfully" });
        }
    }
}
```

**Attack Scenario**:
```sql
-- Attacker with database read access runs:
SELECT CardNumber, CVV, ExpiryDate, CardholderName 
FROM PaymentMethods;

-- Result: All credit card data in plaintext
-- CardNumber: 4111111111111111
-- CVV: 123
-- ExpiryDate: 12/2025
```

**Why This Is Dangerous**:
- Credit card numbers stored in plaintext are immediately usable for fraud
- Database backups, logs, and replicas all contain exposed PAN data
- Violates PCI-DSS requirement 3.4 (render PAN unreadable anywhere it is stored)
- SQL injection, backup theft, or insider threats expose all payment data

**SECURE VERSION**:

```csharp
using System;
using System.Data.SqlClient;
using System.Security.Cryptography;
using System.Text;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;

namespace PaymentApp.Controllers
{
    public class SecurePaymentController : ControllerBase
    {
        private readonly string _connectionString;
        private readonly byte[] _encryptionKey;

        public SecurePaymentController(IConfiguration config)
        {
            _connectionString = config.GetConnectionString("DefaultConnection");
            // Key from Azure Key Vault or similar secure storage
            _encryptionKey = Convert.FromBase64String(
                config["Encryption:DataProtectionKey"]);
        }

        [HttpPost("api/payments/save-card")]
        public IActionResult SaveCreditCard([FromBody] CardRequest request)
        {
            // Encrypt sensitive data before storage
            var encryptedCardNumber = EncryptData(request.CardNumber);
            var lastFourDigits = request.CardNumber.Substring(
                request.CardNumber.Length - 4);

            // Note: CVV should NEVER be stored per PCI-DSS

            using (var connection = new SqlConnection(_connectionString))
            {
                connection.Open();
                var sql = @"INSERT INTO PaymentMethods 
                           (UserId, EncryptedCardNumber, CardLastFour, 
                            ExpiryDate, CardholderName, KeyVersion) 
                           VALUES (@UserId, @EncCard, @LastFour, 
                                   @Expiry, @Name, @KeyVer)";

                using (var cmd = new SqlCommand(sql, connection))
                {
                    cmd.Parameters.AddWithValue("@UserId", request.UserId);
                    cmd.Parameters.AddWithValue("@EncCard", encryptedCardNumber);
                    cmd.Parameters.AddWithValue("@LastFour", lastFourDigits);
                    cmd.Parameters.AddWithValue("@Expiry", request.ExpiryDate);
                    cmd.Parameters.AddWithValue("@Name", request.CardholderName);
                    cmd.Parameters.AddWithValue("@KeyVer", GetCurrentKeyVersion());
                    cmd.ExecuteNonQuery();
                }
            }
            return Ok(new { message = "Card saved securely" });
        }

        private byte[] EncryptData(string plaintext)
        {
            using (var aes = Aes.Create())
            {
                aes.Key = _encryptionKey;
                aes.GenerateIV();

                using (var encryptor = aes.CreateEncryptor())
                {
                    var plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
                    var ciphertext = encryptor.TransformFinalBlock(
                        plaintextBytes, 0, plaintextBytes.Length);

                    // Prepend IV to ciphertext for storage
                    var result = new byte[aes.IV.Length + ciphertext.Length];
                    Buffer.BlockCopy(aes.IV, 0, result, 0, aes.IV.Length);
                    Buffer.BlockCopy(ciphertext, 0, result, aes.IV.Length, 
                                    ciphertext.Length);
                    return result;
                }
            }
        }

        private int GetCurrentKeyVersion() => 1;
    }
}
```

**Key Security Controls**:
- **AES-256 encryption**: Uses strong symmetric encryption for card data at rest
- **Unique IV per encryption**: Each record uses a random IV preventing pattern analysis
- **Key versioning**: Supports key rotation without data loss
- **No CVV storage**: CVV must never be stored per PCI-DSS requirements
- **Masked display data**: Only last 4 digits stored in plaintext for display

Excellent question! Key management is often where encryption implementations fail. Hardcoding keys or storing them alongside encrypted data defeats the purpose entirely. Here's a production-ready implementation using Azure Key Vault with key rotation support.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Concurrent;
using System.Security.Cryptography;
using System.Text;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.Security.KeyVault.Keys;
using Azure.Security.KeyVault.Keys.Cryptography;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;

namespace PaymentApp.Security
{
    public interface IEncryptionService
    {
        Task<EncryptedData> EncryptAsync(string plaintext);
        Task<string> DecryptAsync(EncryptedData encryptedData);
        Task RotateKeyAsync();
    }

    public class EncryptedData
    {
        public byte[] Ciphertext { get; set; }
        public byte[] IV { get; set; }
        public string KeyId { get; set; }
        public byte[] EncryptedDEK { get; set; }  // Data Encryption Key
    }

    public class AzureKeyVaultEncryptionService : IEncryptionService
    {
        private readonly KeyClient _keyClient;
        private readonly ILogger<AzureKeyVaultEncryptionService> _logger;
        private readonly IMemoryCache _cache;
        private readonly string _keyName;
        private readonly ConcurrentDictionary<string, CryptographyClient> _cryptoClients;

        public AzureKeyVaultEncryptionService(
            IConfiguration config,
            ILogger<AzureKeyVaultEncryptionService> logger,
            IMemoryCache cache)
        {
            var vaultUri = new Uri(config["KeyVault:VaultUri"]);
            _keyName = config["KeyVault:EncryptionKeyName"];

            // Use managed identity in production
            _keyClient = new KeyClient(vaultUri, new DefaultAzureCredential());
            _logger = logger;
            _cache = cache;
            _cryptoClients = new ConcurrentDictionary<string, CryptographyClient>();
        }

        public async Task<EncryptedData> EncryptAsync(string plaintext)
        {
            if (string.IsNullOrEmpty(plaintext))
                throw new ArgumentNullException(nameof(plaintext));

            try
            {
                // Get current KEK (Key Encryption Key) from Key Vault
                var kek = await GetCurrentKeyAsync();
                var cryptoClient = GetCryptoClient(kek.Id.ToString());

                // Generate random DEK (Data Encryption Key) for this encryption
                using var aes = Aes.Create();
                aes.KeySize = 256;
                aes.GenerateKey();
                aes.GenerateIV();

                // Encrypt the plaintext with DEK
                byte[] ciphertext;
                using (var encryptor = aes.CreateEncryptor())
                {
                    var plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
                    ciphertext = encryptor.TransformFinalBlock(
                        plaintextBytes, 0, plaintextBytes.Length);
                }

                // Wrap (encrypt) the DEK with KEK from Key Vault
                var wrappedKey = await cryptoClient.WrapKeyAsync(
                    KeyWrapAlgorithm.RsaOaep256, aes.Key);

                _logger.LogInformation(
                    "Data encrypted with key version {KeyId}", 
                    kek.Properties.Version);

                return new EncryptedData
                {
                    Ciphertext = ciphertext,
                    IV = aes.IV,
                    KeyId = kek.Id.ToString(),
                    EncryptedDEK = wrappedKey.EncryptedKey
                };
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Encryption failed");
                throw new CryptographicException(
                    "Failed to encrypt data securely", ex);
            }
        }

        public async Task<string> DecryptAsync(EncryptedData encryptedData)
        {
            if (encryptedData == null)
                throw new ArgumentNullException(nameof(encryptedData));

            try
            {
                // Get crypto client for the specific key version used
                var cryptoClient = GetCryptoClient(encryptedData.KeyId);

                // Unwrap the DEK using the KEK
                var unwrappedKey = await cryptoClient.UnwrapKeyAsync(
                    KeyWrapAlgorithm.RsaOaep256, encryptedData.EncryptedDEK);

                // Decrypt the ciphertext with the DEK
                using var aes = Aes.Create();
                aes.Key = unwrappedKey.Key;
                aes.IV = encryptedData.IV;

                using var decryptor = aes.CreateDecryptor();
                var plaintextBytes = decryptor.TransformFinalBlock(
                    encryptedData.Ciphertext, 0, encryptedData.Ciphertext.Length);

                return Encoding.UTF8.GetString(plaintextBytes);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, 
                    "Decryption failed for key {KeyId}", encryptedData.KeyId);
                throw new CryptographicException(
                    "Failed to decrypt data", ex);
            }
        }

        public async Task RotateKeyAsync()
        {
            _logger.LogWarning("Initiating key rotation for {KeyName}", _keyName);

            try
            {
                // Create new key version in Key Vault
                var rotatedKey = await _keyClient.RotateKeyAsync(_keyName);

                // Clear key cache to force refresh
                _cache.Remove($"kek_{_keyName}");

                _logger.LogWarning(
                    "Key rotated successfully. New version: {Version}",
                    rotatedKey.Value.Properties.Version);

                // Note: Existing data remains readable because we store KeyId
                // with each encrypted record - old key versions remain in KV
            }
            catch (Exception ex)
            {
                _logger.LogCritical(ex, "Key rotation FAILED");
                throw;
            }
        }

        private async Task<KeyVaultKey> GetCurrentKeyAsync()
        {
            return await _cache.GetOrCreateAsync($"kek_{_keyName}", 
                async entry =>
            {
                entry.AbsoluteExpirationRelativeToNow = TimeSpan.FromMinutes(5);
                return await _keyClient.GetKeyAsync(_keyName);
            });
        }

        private CryptographyClient GetCryptoClient(string keyId)
        {
            return _cryptoClients.GetOrAdd(keyId, id =>
                new CryptographyClient(new Uri(id), new DefaultAzureCredential()));
        }
    }
}
```

**Key Rotation Background Service**:

```csharp
using Microsoft.Extensions.Hosting;

namespace PaymentApp.Services
{
    public class KeyRotationService : BackgroundService
    {
        private readonly IEncryptionService _encryptionService;
        private readonly ILogger<KeyRotationService> _logger;
        private readonly TimeSpan _rotationInterval = TimeSpan.FromDays(90);

        public KeyRotationService(
            IEncryptionService encryptionService,
            ILogger<KeyRotationService> logger)
        {
            _encryptionService = encryptionService;
            _logger = logger;
        }

        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
        {
            while (!stoppingToken.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(_rotationInterval, stoppingToken);
                    await _encryptionService.RotateKeyAsync();

                    _logger.LogInformation(
                        "Automatic key rotation completed at {Time}", 
                        DateTime.UtcNow);
                }
                catch (OperationCanceledException)
                {
                    break;
                }
                catch (Exception ex)
                {
                    _logger.LogCritical(ex, 
                        "Key rotation failed - manual intervention required");
                }
            }
        }
    }
}
